import React, { useState, useEffect } from 'react';

function App() {
  const [books, setBooks] = useState([]);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [cart, setCart] = useState([]);

  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authMode, setAuthMode] = useState('login');
  const [authError, setAuthError] = useState(null);

  const [showCheckoutModal, setShowCheckoutModal] = useState(false);

  const [sortBy, setSortBy] = useState('none');
  const [currentPage, setCurrentPage] = useState(1);
  const booksPerPage = 10;

  const [isAdmin, setIsAdmin] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newAuthor, setNewAuthor] = useState('');
  const [newPrice, setNewPrice] = useState('');
  const [newCategory, setNewCategory] = useState('Stories');
  const [showAddModal, setShowAddModal] = useState(false);

  useEffect(() => {
    if (isLoggedIn) {
      fetch('http://localhost:5000/api/products')
        .then(res => {
          if (!res.ok) {
            throw new Error('Server returned status: ' + res.status);
          }
          return res.json();
        })
        .then(data => setBooks(data))
        .catch(err => {
          console.error(err);
          setError('Failed to load books: ' + err.message);
        });
    }
  }, [isLoggedIn]);

  const handleAuth = (e) => {
    e.preventDefault();
    setAuthError(null);

    if (authMode === 'login') {
      if (email === 'admin@deci.com' && password === '0000') {
        setIsAdmin(true);
        setUsername('Admin');
        setIsLoggedIn(true);
        return;
      }

      fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      })
        .then(res => {
          if (!res.ok) {
            throw new Error('Invalid email or password');
          }
          return res.json();
        })
        .then(data => {
          if (email === 'admin@deci.com') {
            setIsAdmin(true);
            setUsername('Admin');
          } else {
            const nameFromEmail = email.split('@')[0];
            setUsername(nameFromEmail.charAt(0).toUpperCase() + nameFromEmail.slice(1));
          }
          setIsLoggedIn(true);
        })
        .catch(err => {
          setAuthError(err.message);
        });
    } else {
      if (username.trim() === '') {
        setAuthError('Please enter a username');
        return;
      }
      setIsLoggedIn(true);
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setIsAdmin(false);
    setEmail('');
    setPassword('');
    setCart([]);
    if (authMode === 'login') setUsername('');
  };

  const addToCart = (book) => {
    setCart([...cart, book]);
  };

  const removeFromCart = (indexToRemove) => {
    setCart(cart.filter((_, index) => index !== indexToRemove));
  };

  const confirmCheckout = () => {
    setCart([]);
    setShowCheckoutModal(false);
  };

  const handleAddBook = (e) => {
    e.preventDefault();
    
    const newBookId = Date.now(); 
    const bookData = { 
      id: newBookId, 
      title: newTitle, 
      author: newAuthor, 
      price: parseFloat(newPrice), 
      category: newCategory 
    };
    
    setBooks([...books, bookData]);
    setShowAddModal(false);
    setNewTitle(''); 
    setNewAuthor(''); 
    setNewPrice('');

    fetch('http://localhost:5000/api/products', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        title: newTitle,
        author: newAuthor,
        price: parseFloat(newPrice),
        category: newCategory
      })
    })
    .then(res => {
      if (!res.ok) console.error('Server failed to save, but added locally');
      return res.json();
    })
    .catch(err => console.error('Network error, book kept locally:', err));
  };

  const handleDeleteBook = (id) => {
    fetch(`http://localhost:5000/api/products/${id}`, { method: 'DELETE' })
      .then(() => {
        setBooks(books.filter(book => book.id !== id));
      });
  };

  const cartTotal = cart.reduce((total, book) => total + book.price, 0);

  const filtered = books.filter(book => {
    const matchesSearch = book.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          book.author.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'All' || book.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const sortedBooks = [...filtered].sort((a, b) => {
    if (sortBy === 'low-to-high') return a.price - b.price;
    if (sortBy === 'high-to-low') return b.price - a.price;
    return 0;
  });

  const indexOfLastBook = currentPage * booksPerPage;
  const indexOfFirstBook = indexOfLastBook - booksPerPage;
  const currentBooks = sortedBooks.slice(indexOfFirstBook, indexOfLastBook);
  const totalPages = Math.ceil(sortedBooks.length / booksPerPage);

  if (!isLoggedIn) {
    return (
      <div style={{ display: 'flex', minHeight: '100vh', backgroundColor: '#090d16', fontFamily: '"Plus Jakarta Sans", "Inter", system-ui, sans-serif', backgroundImage: 'radial-gradient(circle at 80% 20%, rgba(99, 102, 241, 0.15) 0%, transparent 50%), radial-gradient(circle at 20% 80%, rgba(244, 63, 94, 0.1) 0%, transparent 50%)' }}>
        <div style={{ flex: '1', display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '0 60px', backgroundColor: 'rgba(13, 20, 35, 0.85)', backdropFilter: 'blur(20px)', borderRight: '1px solid rgba(255, 255, 255, 0.06)', maxWidth: '460px', width: '100%', boxSizing: 'border-box' }}>
          <div style={{ marginBottom: '40px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '32px' }}>
              <div style={{ width: '12px', height: '12px', borderRadius: '50%', backgroundColor: '#6366f1' }}></div>
              <span style={{ fontWeight: '800', color: '#ffffff', fontSize: '20px', letterSpacing: '-0.5px' }}>Z-BOOK</span>
            </div>
            <h2 style={{ fontSize: '32px', fontWeight: '700', color: '#ffffff', margin: '0 0 10px 0', letterSpacing: '-0.5px' }}>
              {authMode === 'login' ? 'Welcome Back' : 'Create New Account'}
            </h2>
            <p style={{ color: '#94a3b8', fontSize: '15px', margin: 0, lineHeight: '1.5' }}>
              {authMode === 'login' ? 'Sign in to explore the latest exclusive books and stories.' : 'Join us now and start your journey into the world of reading.'}
            </p>
          </div>

          {authError && (
            <div style={{ color: '#f43f5e', backgroundColor: 'rgba(244, 63, 94, 0.1)', border: '1px solid rgba(244, 63, 94, 0.2)', padding: '12px 16px', fontSize: '14px', borderRadius: '12px', marginBottom: '24px' }}>
              {authError}
            </div>
          )}

          <form onSubmit={handleAuth} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            {authMode === 'signup' && (
              <div>
                <input 
                  id="username-input"
                  type="text" 
                  placeholder="Username"
                  required
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  style={{ width: '100%', padding: '14px 16px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.1)', backgroundColor: 'rgba(15,23,42,0.6)', color: '#ffffff', boxSizing: 'border-box', fontSize: '15px', outline: 'none' }}
                />
              </div>
            )}

            <div>
              <input 
                id="email-input"
                type="email" 
                placeholder="Email Address"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                style={{ width: '100%', padding: '14px 16px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.1)', backgroundColor: 'rgba(15,23,42,0.6)', color: '#ffffff', boxSizing: 'border-box', fontSize: '15px', outline: 'none' }}
              />
            </div>

            <div>
              <input 
                id="password-input"
                type="password" 
                placeholder="Password"
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                style={{ width: '100%', padding: '14px 16px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.1)', backgroundColor: 'rgba(15,23,42,0.6)', color: '#ffffff', boxSizing: 'border-box', fontSize: '15px', outline: 'none' }}
              />
            </div>

            <button type="submit" style={{ width: '100%', background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)', color: '#ffffff', border: 'none', padding: '14px', borderRadius: '12px', cursor: 'pointer', fontWeight: '600', fontSize: '16px', marginTop: '10px', boxShadow: '0 4px 20px rgba(79, 70, 229, 0.3)' }}>
              {authMode === 'login' ? 'Sign In' : 'Confirm Registration'}
            </button>

            <div style={{ fontSize: '14px', color: '#94a3b8', textAlign: 'center', marginTop: '12px' }}>
              {authMode === 'login' ? "Don't have an account? " : 'Already have an account? '}
              <span 
                onClick={() => { setAuthMode(authMode === 'login' ? 'signup' : 'login'); setAuthError(null); }}
                style={{ color: '#818cf8', cursor: 'pointer', fontWeight: '600', textDecoration: 'none' }}
              >
                {authMode === 'login' ? 'Create one now' : 'Sign In'}
              </span>
            </div>
          </form>
        </div>

        <div style={{ flex: '1', position: 'relative', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <img 
            src="https://images.unsplash.com/photo-1507842217343-583bb7270b66?auto=format&fit=crop&w=1600&q=80" 
            alt="Z-BOOK Aesthetic Library" 
            style={{ position: 'absolute', width: '100%', height: '100%', objectFit: 'cover', zIndex: 1 }}
          />
          <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'linear-gradient(135deg, rgba(9,13,22,0.95) 0%, rgba(79,70,229,0.4) 100%)', zIndex: 2 }}></div>
          <div style={{ position: 'relative', zIndex: 3, padding: '40px', color: '#ffffff', maxWidth: '560px', textAlign: 'center' }}>
            <h1 style={{ fontSize: '46px', fontWeight: '800', margin: '0 0 20px 0', lineHeight: '1.2', letterSpacing: '-1px' }}>Discover new worlds between pages.</h1>
            <p style={{ fontSize: '18px', color: '#cbd5e1', margin: 0, lineHeight: '1.6', fontWeight: '400' }}>Z-BOOK Bookstore provides an immersive experience to access thousands of international titles, scientific research, and inspiring stories all in one modern browsing space.</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={{ fontFamily: '"Plus Jakarta Sans", "Inter", system-ui, sans-serif', backgroundColor: '#070a13', color: '#f8fafc', minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: 'rgba(13, 20, 35, 0.75)', backdropFilter: 'blur(20px)', padding: '0 6%', height: '76px', borderBottom: '1px solid rgba(255,255,255,0.06)', position: 'sticky', top: 0, zIndex: 100 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '48px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <div style={{ width: '14px', height: '14px', borderRadius: '50%', backgroundColor: '#6366f1', boxShadow: '0 0 12px #6366f1' }}></div>
            <span style={{ fontWeight: '800', color: '#ffffff', fontSize: '22px', letterSpacing: '-0.5px' }}>Z-BOOK<span style={{ color: '#4f46e5' }}>.</span></span>
          </div>
        </div>
        
        <div style={{ display: 'flex', alignItems: 'center', gap: '24px' }}>
          <span style={{ fontSize: '14px', color: '#94a3b8' }}>Active User: <strong style={{ color: '#ffffff', fontWeight: '600' }}>{username}</strong></span>
          <button onClick={handleLogout} style={{ backgroundColor: 'rgba(244, 63, 94, 0.1)', color: '#f43f5e', border: '1px solid rgba(244, 63, 94, 0.2)', padding: '8px 18px', borderRadius: '10px', cursor: 'pointer', fontSize: '13px', fontWeight: '600', transition: 'all 0.2s' }}>Sign Out</button>
        </div>
      </div>

      <div style={{ position: 'relative', height: '360px', overflow: 'hidden', display: 'flex', alignItems: 'center', padding: '0 6%' }}>
        <img 
          src="https://images.unsplash.com/photo-1524995997946-a1c2e315a42f?auto=format&fit=crop&w=1600&q=80" 
          alt="Library Banner Decor" 
          style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', objectFit: 'cover', zIndex: 1 }}
        />
        <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'linear-gradient(90deg, #070a13 35%, rgba(7,10,19,0.6) 70%, transparent 100%)', zIndex: 2 }}></div>
        <div style={{ position: 'relative', zIndex: 3, maxWidth: '600px' }}>
          <span style={{ background: 'rgba(99, 102, 241, 0.15)', color: '#818cf8', padding: '6px 12px', borderRadius: '8px', fontSize: '12px', fontWeight: '700', textTransform: 'uppercase', display: 'inline-block', marginBottom: '16px', border: '1px solid rgba(99, 102, 241, 0.2)' }}>Exclusive Limited Offer</span>
          <h2 style={{ fontSize: '42px', fontWeight: '800', margin: '0 0 14px 0', color: '#ffffff', lineHeight: '1.2', letterSpacing: '-0.5px' }}>Build your unique digital library today.</h2>
          <p style={{ fontSize: '16px', color: '#94a3b8', margin: 0, lineHeight: '1.6' }}>Browse our carefully curated collection of novels, scientific, and technological books designed to enrich your intellectual passion.</p>
        </div>
      </div>

      {isAdmin ? (
        <div style={{ padding: '48px 6%', flex: 1 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px', backgroundColor: '#0d1423', border: '1px solid rgba(255,255,255,0.06)', padding: '24px 32px', borderRadius: '20px' }}>
            <div>
              <h2 style={{ margin: 0, color: '#ffffff', fontSize: '22px', fontWeight: '700' }}>Control Panel & Inventory Management</h2>
              <p style={{ margin: '6px 0 0 0', color: '#94a3b8', fontSize: '14px' }}>Seamlessly add, edit, and remove titles and books displayed in the shop.</p>
            </div>
            <button onClick={() => setShowAddModal(true)} style={{ background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)', color: '#ffffff', border: 'none', padding: '12px 24px', borderRadius: '12px', cursor: 'pointer', fontSize: '14px', fontWeight: '600', boxShadow: '0 4px 12px rgba(16, 185, 129, 0.2)' }}>Index New Book</button>
          </div>

          <div style={{ backgroundColor: '#0d1423', border: '1px solid rgba(255,255,255,0.06)', borderRadius: '20px', overflow: 'hidden' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
              <thead>
                <tr style={{ borderBottom: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.4)' }}>
                  <th style={{ padding: '16px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase' }}>Book Title</th>
                  <th style={{ padding: '16px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase' }}>Author</th>
                  <th style={{ padding: '16px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase' }}>Category</th>
                  <th style={{ padding: '16px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase' }}>Price</th>
                  <th style={{ padding: '16px 24px', color: '#94a3b8', fontSize: '13px', fontWeight: '600', textTransform: 'uppercase', textAlign: 'right' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {books.map(book => (
                  <tr key={book.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.04)' }}>
                    <td style={{ padding: '18px 24px', fontWeight: '600', color: '#ffffff', fontSize: '15px' }}>{book.title}</td>
                    <td style={{ padding: '18px 24px', color: '#cbd5e1', fontSize: '15px' }}>{book.author}</td>
                    <td style={{ padding: '18px 24px' }}>
                      <span style={{ backgroundColor: 'rgba(99, 102, 241, 0.12)', color: '#818cf8', padding: '4px 10px', borderRadius: '8px', fontSize: '12px', fontWeight: '600', border: '1px solid rgba(99, 102, 241, 0.15)' }}>{book.category}</span>
                    </td>
                    <td style={{ padding: '18px 24px', color: '#34d399', fontWeight: '700', fontSize: '16px' }}>${book.price.toFixed(2)}</td>
                    <td style={{ padding: '18px 24px', textAlign: 'right' }}>
                      <button onClick={() => handleDeleteBook(book.id)} style={{ backgroundColor: 'rgba(244, 63, 94, 0.1)', color: '#f43f5e', border: 'none', padding: '6px 14px', borderRadius: '8px', cursor: 'pointer', fontSize: '13px', fontWeight: '600' }}>Remove Book</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {books.length === 0 && (
              <div style={{ textAlign: 'center', padding: '48px', color: '#64748b', fontSize: '15px' }}>No products available in the catalog yet.</div>
            )}
          </div>
        </div>
      ) : (
        <div style={{ display: 'flex', padding: '48px 6%', gap: '40px', alignItems: 'flex-start', flex: 1 }}>
          
          <div style={{ flex: '1' }}>
            {error && (
              <div style={{ color: '#f43f5e', backgroundColor: 'rgba(244, 63, 94, 0.1)', border: '1px solid rgba(244, 63, 94, 0.15)', padding: '16px', borderRadius: '16px', marginBottom: '32px', fontSize: '14px' }}>
                {error}
              </div>
            )}

            <div style={{ display: 'flex', flexDirection: 'column', gap: '24px', marginBottom: '40px', backgroundColor: '#0d1423', border: '1px solid rgba(255,255,255,0.04)', padding: '28px', borderRadius: '24px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '20px' }}>
                <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                  {['All', 'Stories', 'Science', 'History', 'Tech'].map(category => (
                    <button 
                      key={category}
                      onClick={() => { setSelectedCategory(category); setCurrentPage(1); }}
                      style={{
                        padding: '10px 20px',
                        borderRadius: '12px',
                        border: '1px solid rgba(255,255,255,0.05)',
                        cursor: 'pointer',
                        fontSize: '14px',
                        fontWeight: '600',
                        backgroundColor: selectedCategory === category ? '#6366f1' : 'rgba(15, 23, 42, 0.6)',
                        color: selectedCategory === category ? '#ffffff' : '#94a3b8',
                        boxShadow: selectedCategory === category ? '0 4px 14px rgba(99, 102, 241, 0.3)' : 'none',
                        transition: 'all 0.2s ease'
                      }}
                    >
                      {category}
                    </button>
                  ))}
                </div>

                <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                  <input 
                    type="text" 
                    placeholder="Search books or authors..." 
                    value={searchTerm}
                    onChange={(e) => { setSearchTerm(e.target.value); setCurrentPage(1); }}
                    style={{ 
                      padding: '12px 18px', 
                      width: '260px', 
                      borderRadius: '12px',
                      border: '1px solid rgba(255,255,255,0.08)', 
                      backgroundColor: 'rgba(15, 23, 42, 0.6)',
                      color: '#ffffff',
                      fontSize: '14px',
                      outline: 'none'
                    }}
                  />

                  <select 
                    id="sort-select"
                    value={sortBy} 
                    onChange={(e) => { setSortBy(e.target.value); setCurrentPage(1); }}
                    style={{ padding: '12px 16px', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.6)', color: '#ffffff', outline: 'none', cursor: 'pointer', fontSize: '14px' }}
                  >
                    <option value="none">Sort: Default</option>
                    <option value="low-to-high">Price: Low to High</option>
                    <option value="high-to-low">Price: High to Low</option>
                  </select>
                </div>
              </div>
            </div>
            
            <div style={{ 
              display: 'grid', 
              gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', 
              gap: '32px'
            }}>
              {currentBooks.map(book => (
                <div key={book.id} style={{ 
                  backgroundColor: '#0d1423', 
                  border: '1px solid rgba(255,255,255,0.05)',
                  borderRadius: '20px',
                  display: 'flex', 
                  flexDirection: 'column',
                  overflow: 'hidden',
                  boxShadow: '0 4px 20px rgba(0,0,0,0.15)'
                }}>
                  <div style={{ width: '100%', height: '260px', overflow: 'hidden', backgroundColor: '#131b2e' }}>
                    <img 
                      src={
                        book.category === 'Science' ? 'https://images.unsplash.com/photo-1507679799987-c73779587ccf?auto=format&fit=crop&w=600&q=80' :
                        book.category === 'Tech' ? 'https://images.unsplash.com/photo-1488590528505-98d2b5aba04b?auto=format&fit=crop&w=600&q=80' :
                        book.category === 'History' ? 'https://images.unsplash.com/photo-1461360370896-922624d12aa1?auto=format&fit=crop&w=600&q=80' :
                        'https://images.unsplash.com/photo-1434030216411-0b793f4b4173?auto=format&fit=crop&w=600&q=80'
                      } 
                      alt="Publication Cover" 
                      style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                    />
                  </div>
                  <div style={{ padding: '24px', display: 'flex', flexDirection: 'column', flex: 1 }}>
                    <span style={{ fontSize: '11px', fontWeight: '700', color: '#818cf8', textTransform: 'uppercase', marginBottom: '8px', display: 'block' }}>{book.category}</span>
                    <h3 style={{ margin: '0 0 6px 0', color: '#ffffff', fontSize: '18px', fontWeight: '700', lineHeight: '1.4' }}>{book.title}</h3>
                    <p style={{ margin: '0 0 20px 0', color: '#94a3b8', fontSize: '14px' }}>By {book.author}</p>
                    
                    <div style={{ marginTop: 'auto', display: 'flex', alignItems: 'center', justifyContent: 'space-between', paddingTop: '16px', borderTop: '1px solid rgba(255,255,255,0.04)' }}>
                      <span style={{ fontWeight: '700', color: '#34d399', fontSize: '20px' }}>${book.price.toFixed(2)}</span>
                      <button 
                        onClick={() => addToCart(book)}
                        style={{ 
                          background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)', 
                          color: '#ffffff', 
                          border: 'none', 
                          padding: '10px 16px', 
                          borderRadius: '10px',
                          cursor: 'pointer', 
                          fontWeight: '600',
                          fontSize: '13px',
                          boxShadow: '0 4px 12px rgba(79, 70, 229, 0.2)'
                        }}
                      >
                        Add to Cart
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {currentBooks.length === 0 && (
              <p style={{ textAlign: 'center', color: '#64748b', fontSize: '15px', marginTop: '48px' }}>No books match your current configurations.</p>
            )}

            {totalPages > 1 && (
              <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '12px', marginTop: '40px' }}>
                <button 
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage(prev => prev - 1)}
                  style={{ padding: '8px 16px', borderRadius: '10px', border: '1px solid rgba(255,255,255,0.06)', backgroundColor: currentPage === 1 ? 'transparent' : 'rgba(30, 41, 59, 0.4)', color: currentPage === 1 ? '#475569' : '#ffffff', cursor: currentPage === 1 ? 'not-allowed' : 'pointer', fontSize: '14px' }}
                >
                  Previous
                </button>
                <span style={{ fontSize: '14px', color: '#94a3b8', padding: '0 12px' }}>Page {currentPage} of {totalPages}</span>
                <button 
                  disabled={currentPage === totalPages}
                  onClick={() => setCurrentPage(prev => prev + 1)}
                  style={{ padding: '8px 16px', borderRadius: '10px', border: '1px solid rgba(255,255,255,0.06)', backgroundColor: currentPage === totalPages ? 'transparent' : 'rgba(30, 41, 59, 0.4)', color: currentPage === totalPages ? '#475569' : '#ffffff', cursor: currentPage === totalPages ? 'not-allowed' : 'pointer', fontSize: '14px' }}
                >
                  Next
                </button>
              </div>
            )}
          </div>

          <div style={{ 
            width: '340px', 
            backgroundColor: '#0d1423', 
            padding: '28px', 
            borderRadius: '24px',
            border: '1px solid rgba(255,255,255,0.05)',
            boxSizing: 'border-box',
            position: 'sticky',
            top: '116px'
          }}>
            <h2 style={{ color: '#ffffff', paddingBottom: '14px', borderBottom: '1px solid rgba(255,255,255,0.06)', margin: 0, fontSize: '18px', fontWeight: '700' }}>Shopping Cart ({cart.length})</h2>
            
            <div style={{ margin: '20px 0', minHeight: '140px', maxHeight: '320px', overflowY: 'auto' }}>
              {cart.length === 0 ? (
                <div style={{ color: '#64748b', fontSize: '14px', paddingTop: '32px', textAlign: 'center' }}>
                  No products items in the cart.
                </div>
              ) : (
                <ul style={{ listStyle: 'none', padding: 0, margin: 0, display: 'flex', flexDirection: 'column', gap: '12px' }}>
                  {cart.map((item, index) => (
                    <li key={index} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', fontSize: '14px', backgroundColor: 'rgba(15, 23, 42, 0.4)', padding: '12px', borderRadius: '10px', border: '1px solid rgba(255,255,255,0.02)' }}>
                      <div style={{ flex: 1, paddingRight: '12px' }}>
                        <span style={{ display: 'block', fontWeight: '600', color: '#ffffff', marginBottom: '2px' }}>{item.title}</span>
                        <span style={{ color: '#34d399', fontWeight: '600' }}>${item.price.toFixed(2)}</span>
                      </div>
                      <button 
                        onClick={() => removeFromCart(index)}
                        style={{ backgroundColor: 'transparent', color: '#f43f5e', border: 'none', cursor: 'pointer', fontSize: '12px', fontWeight: '500' }}
                      >
                        Remove
                      </button>
                    </li>
                  ))}
                </ul>
              )}
            </div>

            <div style={{ borderTop: '1px solid rgba(255,255,255,0.06)', paddingTop: '20px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '15px', marginBottom: '20px' }}>
                <span style={{ color: '#94a3b8' }}>Total Amount</span>
                <span style={{ color: '#34d399', fontWeight: '700', fontSize: '22px' }}>${cartTotal.toFixed(2)}</span>
              </div>
              <button 
                onClick={() => setShowCheckoutModal(true)}
                disabled={cart.length === 0}
                style={{ 
                  background: cart.length === 0 ? '#1e293b' : 'linear-gradient(135deg, #10b981 0%, #059669 100%)', 
                  color: cart.length === 0 ? '#475569' : '#ffffff', 
                  border: 'none', 
                  padding: '14px', 
                  borderRadius: '12px',
                  cursor: cart.length === 0 ? 'not-allowed' : 'pointer', 
                  fontWeight: '600',
                  width: '100%',
                  fontSize: '15px',
                  boxShadow: cart.length === 0 ? 'none' : '0 4px 12px rgba(16, 185, 129, 0.2)'
                }}
              >
                Execute Secure Purchase
              </button>
            </div>
          </div>
        </div>
      )}

      {showCheckoutModal && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(9, 13, 22, 0.7)', backdropFilter: 'blur(10px)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000 }}>
          <div style={{ backgroundColor: '#0d1423', padding: '40px', width: '100%', maxWidth: '440px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.08)', boxSizing: 'border-box', textAlign: 'center' }}>
            <div style={{ color: '#10b981', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: '56px', height: '56px', backgroundColor: 'rgba(16, 185, 129, 0.1)', borderRadius: '50%', fontSize: '24px', marginBottom: '20px', fontWeight: 'bold' }}>✓</div>
            <h3 style={{ margin: '0 0 10px 0', color: '#ffffff', fontSize: '22px', fontWeight: '700' }}>Purchase Complete</h3>
            <p style={{ color: '#94a3b8', fontSize: '15px', marginBottom: '28px', lineHeight: '1.6' }}>
              Thank you, <strong>{username}</strong>. We have confirmed your request for <strong>{cart.length}</strong> items for a total net consideration of <strong>${cartTotal.toFixed(2)}</strong>.
            </p>
            <button 
              onClick={confirmCheckout}
              style={{ background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)', color: '#ffffff', border: 'none', padding: '12px 32px', borderRadius: '12px', cursor: 'pointer', fontSize: '15px', fontWeight: '600' }}
            >
              Back to Store
            </button>
          </div>
        </div>
      )}

      {showAddModal && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(9, 13, 22, 0.7)', backdropFilter: 'blur(10px)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 }}>
          <form onSubmit={handleAddBook} style={{ backgroundColor: '#0d1423', padding: '36px', width: '100%', maxWidth: '420px', borderRadius: '24px', border: '1px solid rgba(255,255,255,0.08)', boxSizing: 'border-box' }}>
            <h3 style={{ marginTop: 0, marginBottom: '24px', color: '#ffffff', fontSize: '20px', fontWeight: '700' }}>Index New Publication</h3>
            <div style={{ marginBottom: '18px' }}>
              <label htmlFor="new-title" style={{ display: 'block', marginBottom: '6px', color: '#94a3b8', fontSize: '13px', fontWeight: '600' }}>Asset Title</label>
              <input id="new-title" type="text" required value={newTitle} onChange={(e) => setNewTitle(e.target.value)} style={{ width: '100%', padding: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.5)', color: '#ffffff', borderRadius: '12px', boxSizing: 'border-box', outline: 'none', fontSize: '15px' }} />
            </div>
            <div style={{ marginBottom: '18px' }}>
              <label htmlFor="new-author" style={{ display: 'block', marginBottom: '6px', color: '#94a3b8', fontSize: '13px', fontWeight: '600' }}>Primary Originator</label>
              <input id="new-author" type="text" required value={newAuthor} onChange={(e) => setNewAuthor(e.target.value)} style={{ width: '100%', padding: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.5)', color: '#ffffff', borderRadius: '12px', boxSizing: 'border-box', outline: 'none', fontSize: '15px' }} />
            </div>
            <div style={{ marginBottom: '18px' }}>
              <label htmlFor="new-price" style={{ display: 'block', marginBottom: '6px', color: '#94a3b8', fontSize: '13px', fontWeight: '600' }}>Corporate Valuation ($)</label>
              <input id="new-price" type="number" step="0.01" required value={newPrice} onChange={(e) => setNewPrice(e.target.value)} style={{ width: '100%', padding: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.5)', color: '#ffffff', borderRadius: '12px', boxSizing: 'border-box', outline: 'none', fontSize: '15px' }} />
            </div>
            <div style={{ marginBottom: '28px' }}>
              <label htmlFor="new-category" style={{ display: 'block', marginBottom: '6px', color: '#94a3b8', fontSize: '13px', fontWeight: '600' }}>Systemic Classification</label>
              <select id="new-category" value={newCategory} onChange={(e) => setNewCategory(e.target.value)} style={{ width: '100%', padding: '12px', border: '1px solid rgba(255,255,255,0.08)', backgroundColor: 'rgba(15, 23, 42, 0.5)', color: '#ffffff', borderRadius: '12px', outline: 'none', fontSize: '15px', cursor: 'pointer' }}>
                <option value="Stories">Stories</option>
                <option value="Science">Science</option>
                <option value="History">History</option>
                <option value="Tech">Tech</option>
              </select>
            </div>
            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px' }}>
              <button type="button" onClick={() => setShowAddModal(false)} style={{ padding: '10px 18px', background: 'transparent', border: '1px solid rgba(255,255,255,0.08)', color: '#94a3b8', borderRadius: '12px', cursor: 'pointer', fontSize: '14px', fontWeight: '600' }}>Cancel</button>
              <button type="submit" style={{ padding: '10px 22px', backgroundColor: '#10b981', color: '#ffffff', border: 'none', borderRadius: '12px', cursor: 'pointer', fontSize: '14px', fontWeight: '600' }}>Commit Entry</button>
            </div>
          </form>
        </div>
      )}

      <footer style={{ backgroundColor: '#090d16', color: '#64748b', padding: '32px 6%', fontSize: '13px', marginTop: 'auto', borderTop: '1px solid rgba(255,255,255,0.04)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', gap: '20px' }}>
          <div>© {new Date().getFullYear()} Z-BOOK Corporation. All rights reserved.</div>
        </div>
      </footer>

    </div>
  );
}

export default App;
